import React, { useEffect, useState } from "react";
import axios from "axios";
import { motion } from "framer-motion";

const NotesCards = () => {

    const userId = "user123";

    const [todos, setTodos] = useState([]);
    const [categories, setCategories] = useState([]);

    const [search, setSearch] = useState("");
    const [selectedCategory, setSelectedCategory] = useState("");

    // FETCH TODOS
    const fetchTodos = async () => {
        try {
            const res = await axios.get(
                `http://localhost:5001/api/todos?userId=${userId}`
            );
            setTodos(res.data);
        } catch (err) {
            console.error("TODO ERROR 👉", err);
        }
    };

    // FETCH CATEGORIES
    const fetchCategories = async () => {
        try {
            const res = await axios.get(
                `http://localhost:5001/api/categories?userId=${userId}`
            );
            setCategories(res.data);
        } catch (err) {
            console.error("CATEGORY ERROR 👉", err);
        }
    };

    const getCategoryColor = (categoryName) => {
        const found = categories.find(
            (cat) => cat.name === categoryName
        );
        return found ? found.color : "#6b7280";
    };

    useEffect(() => {
        fetchTodos();
        fetchCategories();
    }, []);

    // TOGGLE
    const handleToggle = async (id) => {
        try {
            await axios.put(
                `http://localhost:5001/api/todos/toggle/${id}`
            );
            fetchTodos();
        } catch (err) {
            console.error(err);
        }
    };

    // FILTER
    const filteredTodos = todos.filter((todo) => {

        const matchesSearch =
            todo.title.toLowerCase().includes(search.toLowerCase()) ||
            (todo.description || "")
                .toLowerCase()
                .includes(search.toLowerCase());

        const matchesCategory =
            selectedCategory === "" ||
            todo.category === selectedCategory;

        return matchesSearch && matchesCategory;
    });

    return (
        <div className=" p-6">

            {/* HEADER */}


            {/* SEARCH + CATEGORY */}
            <div className="flex flex-col md:flex-row gap-4 mb-8 max-w-5xl mx-auto">

                <input
                    type="text"
                    placeholder="🔍 Search tasks..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="flex-1 px-5 py-3 rounded-2xl bg-white/10 backdrop-blur-lg border border-white/20 text-white placeholder-white/60 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition"
                />

                <select
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                    className="px-5 py-3 rounded-2xl bg-white/10 backdrop-blur-lg border border-white/20 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition"
                >
                    <option value="" className="text-black">
                        All Categories
                    </option>

                    {categories.map((cat) => (
                        <option
                            key={cat._id}
                            value={cat.name}
                            className="text-black"
                        >
                            {cat.name}
                        </option>
                    ))}
                </select>

            </div>

            {/* CARDS */}
            <motion.div
                layout
                className="grid sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6"
            >

                {filteredTodos.length === 0 ? (
                    <p className="text-white text-center col-span-full text-lg">
                        No Tasks Found
                    </p>
                ) : (
                    filteredTodos.map((todo) => (

                        <motion.div
                            key={todo._id}
                            initial={{ opacity: 0, y: 40 }}
                            animate={{ opacity: 1, y: 0 }}
                            whileHover={{ scale: 1.05 }}
                            transition={{ duration: 0.3 }}
                            className="relative bg-white/10 overflow-auto backdrop-blur-xl border border-white/20 rounded-2xl p-5 text-white shadow-xl flex flex-col justify-between h-[240px] hover:shadow-indigo-500/30"
                        >

                            {/* CATEGORY BADGE */}
                            <span
                                className="text-xs w-fit px-3 py-1 rounded-full font-medium"
                                style={{
                                    backgroundColor: getCategoryColor(todo.category),
                                }}
                            >
                                {todo.category}
                            </span>

                            {/* CONTENT */}
                            <div>
                                <h3 className="text-lg font-semibold mt-2 truncate">
                                    {todo.title}
                                </h3>

                                <p className="text-sm text-white/70 mt-2 line-clamp-3">
                                    {todo.description}
                                </p>
                            </div>

                            {/* BUTTON */}
                            <div className="mt-4">
                                {todo.completed ? (
                                    <button className="w-full py-2 rounded-xl bg-green-500/90 hover:bg-green-500 transition font-medium shadow">
                                        ✅ Completed
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => handleToggle(todo._id)}
                                        className="w-full py-2 rounded-xl bg-white text-black hover:bg-gray-200 transition font-medium shadow"
                                    >
                                        Mark as Completed
                                    </button>
                                )}
                            </div>

                            {/* LEFT COLOR BAR */}
                            <div
                                className="absolute left-0 top-0 h-full w-1 rounded-l-2xl"
                                style={{
                                    backgroundColor: getCategoryColor(todo.category),
                                }}
                            />

                        </motion.div>
                    ))
                )}

            </motion.div>

        </div>
    );
};

export default NotesCards;
